import React, { useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { User, GraduationCap, Shield, Eye, EyeOff, Loader2 } from 'lucide-react';

const UnifiedLogin = () => {
  const [formData, setFormData] = useState({
    username: '',
    password: '',
    role: 'student'
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const { studentLogin, teacherLogin, adminLogin } = useAuth();

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!formData.username || !formData.password) return;

    setLoading(true);
    try {
      switch (formData.role) {
        case 'student':
          await studentLogin(formData.username, formData.password);
          break;
        case 'teacher':
          await teacherLogin(formData.username, formData.password);
          break;
        case 'admin':
          await adminLogin(formData.username, formData.password);
          break;
        default:
          throw new Error('Invalid role selected');
      }
    } catch (error) {
      console.error('Login failed:', error);
    } finally {
      setLoading(false);
    }
  };

  const getInputPlaceholder = () => {
    switch (formData.role) {
      case 'student':
        return 'Enter your Student ID';
      case 'teacher':
        return 'Enter your email address';
      case 'admin':
        return 'Enter your username';
      default:
        return 'Enter your username';
    }
  };

  const getInputType = () => {
    return formData.role === 'teacher' ? 'email' : 'text';
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-black via-gray-900 to-black flex items-center justify-center p-4 relative overflow-hidden">
      {/* Background Pattern */}
      <div className="absolute inset-0 opacity-10">
        <div className="absolute inset-0" style={{
          backgroundImage: `radial-gradient(circle at 2px 2px, rgba(251, 146, 60, 0.3) 1px, transparent 1px)`,
          backgroundSize: '40px 40px'
        }}></div>
      </div>

      {/* Main Content */}
      <div className="relative z-10 w-full max-w-md">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-5xl font-bold text-white mb-4">
            <span className="bg-gradient-to-r from-orange-500 to-orange-600 bg-clip-text text-transparent">
              CCS
            </span>
            <span className="text-white"> Management</span>
          </h1>
          <p className="text-lg text-gray-300">College of Computer Studies</p>
          <p className="text-gray-400 mt-2">Sign in to access your account</p>
        </div>

        {/* Login Card */}
        <div className="bg-white rounded-2xl shadow-2xl p-8 border border-orange-500/20">
          {/* Role Selection */}
          <div className="mb-6">
            <label className="block text-sm font-medium text-gray-700 mb-3">Select Role</label>
            <div className="grid grid-cols-3 gap-2">
              {[
                { value: 'student', icon: GraduationCap, label: 'Student' },
                { value: 'teacher', icon: User, label: 'Teacher' },
                { value: 'admin', icon: Shield, label: 'Admin' }
              ].map(({ value, icon: Icon, label }) => (
                <button
                  key={value}
                  type="button"
                  onClick={() => setFormData(prev => ({ ...prev, role: value }))}
                  className={`
                    py-3 px-2 rounded-lg border-2 transition-all duration-200 flex flex-col items-center gap-1
                    ${formData.role === value 
                      ? 'border-orange-500 bg-orange-50 text-orange-600' 
                      : 'border-gray-200 text-gray-600 hover:border-gray-300'
                    }
                  `}
                >
                  <Icon className="w-5 h-5" />
                  <span className="text-xs font-medium">{label}</span>
                </button>
              ))}
            </div>
          </div>

          {/* Login Form */}
          <form onSubmit={handleSubmit} className="space-y-5">
            {/* Username/Email/Student ID Field */}
            <div>
              <label className="label">
                {formData.role === 'student' ? 'Student ID' : formData.role === 'teacher' ? 'Email Address' : 'Username'}
              </label>
              <input
                type={getInputType()}
                name="username"
                value={formData.username}
                onChange={handleInputChange}
                className="input-field"
                placeholder={getInputPlaceholder()}
                required
              />
            </div>

            {/* Password Field */}
            <div>
              <label className="label">Password</label>
              <div className="relative">
                <input
                  type={showPassword ? 'text' : 'password'}
                  name="password"
                  value={formData.password}
                  onChange={handleInputChange}
                  className="input-field pr-12"
                  placeholder="Enter your password"
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 transition-colors"
                >
                  {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                </button>
              </div>
            </div>

            {/* Submit Button */}
            <button
              type="submit"
              disabled={loading}
              className="w-full bg-gradient-to-r from-orange-500 to-orange-600 hover:from-orange-600 hover:to-orange-700 text-white py-3 rounded-xl font-semibold transition-all duration-200 transform hover:scale-[1.02] flex items-center justify-center gap-2"
            >
              {loading ? (
                <>
                  <Loader2 className="w-5 h-5 animate-spin" />
                  Signing in...
                </>
              ) : (
                'Sign In'
              )}
            </button>
          </form>

          {/* Footer Info */}
          <div className="mt-6 text-center">
            <p className="text-gray-500 text-sm">
              Forgot your password? <span className="text-orange-600 font-medium">Contact administrator</span>
            </p>
          </div>
        </div>

        {/* Default Credentials */}
        <div className="mt-8 text-center">
          <p className="text-gray-400 text-sm mb-3">Default Credentials</p>
          <div className="flex flex-wrap justify-center gap-2 text-xs">
            <div className="bg-gray-800/50 backdrop-blur-sm px-3 py-2 rounded-lg border border-gray-700">
              <span className="text-orange-400">Admin:</span> admin / admin123
            </div>
            <div className="bg-gray-800/50 backdrop-blur-sm px-3 py-2 rounded-lg border border-gray-700">
              <span className="text-gray-400">Student:</span> [ID] / password
            </div>
            <div className="bg-gray-800/50 backdrop-blur-sm px-3 py-2 rounded-lg border border-gray-700">
              <span className="text-gray-400">Teacher:</span> email / password
            </div>
          </div>
        </div>

        {/* Status Indicators */}
        <div className="mt-8 text-center">
          <div className="inline-flex items-center space-x-6 text-gray-400 text-sm">
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 bg-orange-500 rounded-full animate-pulse"></div>
              <span>Secure Login</span>
            </div>
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
              <span>Active System</span>
            </div>
            <div className="flex items-center space-x-2">
              <div className="w-2 h-2 bg-blue-500 rounded-full animate-pulse"></div>
              <span>Multi-Role</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default UnifiedLogin;
